import createRequestOptions from"./createRequestOptions.js";import{handleResponse,handleError}from"./handleResponse.js";export default function zlFetch(e,t){return fetchInstance({url:e,...t})}const methods=["get","post","put","patch","delete"];for(const c of methods)zlFetch[c]=function(e,t){return zlFetch(e,t=Object.assign({method:c},t))};async function fetchInstance(t){const e=await getFetch(),r=createRequestOptions({...t,fetch:e});return delete r.fetch,delete r.auth,delete r.debug,delete r.returnError,e.fetch(r.url,r).then(e=>handleResponse(e,t)).then(e=>t.debug?{...e,debug:debugHeaders(r)}:e).catch(handleError)}async function getFetch(){var e;return"undefined"==typeof fetch?{fetch:(e=await import("node-fetch")).default,Headers:e.Headers,Request:e.Request}:{fetch:fetch,Headers:Headers,Request:Request}}function debugHeaders(e){const t=Object.assign({},e),r={};for(var[n,s]of t.headers)r[n]=s;return t.headers=r,t}export{getFetch};